$(function(){
  var pd=parent.document;
  var nm={'airine':'艾莉尼','bathsheba':'拔示巴','lena':'蕾娜','meme':'米姆','belzeebul':'贝尔泽布特'};

  function $id(id){return pd.getElementById(id);}
  function txt(id,v){var el=$id(id);if(el)el.textContent=v!=null?String(v):'--';}

  function ensureDOM(){
    if($id('ml-sb'))return;
    var d=pd.createElement('div');d.id='ml-sb';
    d.style.cssText+='position:fixed;bottom:10px;right:10px;z-index:9999';
    d.innerHTML='<style>#ml-sb{background:#0a0a14;color:#d0d0e8;font:12px Segoe UI,Microsoft YaHei,sans-serif;padding:10px 12px;max-width:300px;border:1px solid #1e1e3a;border-radius:8px}#ml-sb .h{font-size:14px;font-weight:700;color:#7c8aff;margin-bottom:8px;text-align:center}#ml-sb .r{display:flex;justify-content:space-between;padding:3px 0;border-bottom:1px solid rgba(255,255,255,0.04)}#ml-sb .l{color:#7070a0;font-size:11px}#ml-sb .v{text-align:right}#ml-sb .bar{height:4px;background:rgba(255,255,255,0.06);border-radius:2px;margin:2px 0}#ml-sb .fill{height:100%;border-radius:2px;transition:width .4s}#ml-sb .al{font-size:10px;color:#7070a0}#ml-sb .thought{margin-top:6px;padding:6px 8px;background:#12122a;border-radius:4px;font-style:italic;color:#7070a0;font-size:11px;line-height:1.4;border-left:2px solid #1e1e3a}/* Kill old regex statusbar */div[id^=zsb],div[class*=statusbar],div[id*=status]{display:none!important}</style><div class="h" id="mln">加载中...</div><div class="r"><span class="l">好感度</span><span class="v" id="mlav">0/100</span></div><div class="bar"><div class="fill" id="mlab" style="width:0;background:#7070a0"></div></div><div class="al" id="mlal">陌生人</div><div class="r"><span class="l">心情</span><span class="v" id="mlmo">--</span></div><div class="r"><span class="l">穿着</span><span class="v" id="mlcl">--</span></div><div class="thought" id="mlth">...</div>';
    pd.body.appendChild(d);
  }

  function update(){
    ensureDOM();
    try{
      var chat=parent.SillyTavern.getContext().chat;
      if(!chat||!chat.length)return;

      // Read stat_data from message variables (MVU stores it here)
      var st=null, sc='';
      for(var i=chat.length-1;i>=0;i--){
        var vars=chat[i].variables;
        if(!Array.isArray(vars)||!vars.length)continue;
        var vd=vars[0].display_data||vars[0];
        if(vd&&vd.stat_data){
          st=vd.stat_data;
          if(vd.stat_data.selected_character)sc=vd.stat_data.selected_character;
          break;
        }
      }
      if(!st||!st.characters)return;
      // sc may be garbage from MVU internals; use first character key
      var charKeys=Object.keys(st.characters);
      if(!charKeys.length)return;
      // Find character with the most data (highest affection + mood)
      var best=charKeys[0],bestScore=-1;
      for(var k=0;k<charKeys.length;k++){
        var c=st.characters[charKeys[k]]||{};
        var score=(Number(c.affection)||0)*10+(c.mood?1:0)+(c.clothing?1:0);
        if(score>bestScore){bestScore=score;best=charKeys[k];}
      }
      sc=best;

      // Clean MVU noise from values
      function cl(v){if(typeof v==='string')return v.replace(/ ?\(json_patch\)/,'').replace(/^->/,'');return v;}
      var cd=(st.characters||{})[sc]||{};
      var aff=Number(cd.affection)||0;

      var ac,al;
      if(aff>=81){ac='#ff7eb3';al='无条件信任'}
      else if(aff>=61){ac='#7c8aff';al='深厚信赖'}
      else if(aff>=41){ac='#4ade80';al='熟悉亲近'}
      else if(aff>=21){ac='#fbbf24';al='初步信任'}
      else{ac='#7070a0';al='陌生人'}

      txt('mln',nm[sc]||cl(cd.name)||sc);
      $id('mlav').textContent=aff+'/100';
      $id('mlab').style.width=aff+'%';$id('mlab').style.background=ac;
      txt('mlal',al);
      txt('mlmo',cl(cd.mood)||'--');
      txt('mlcl',cl(cd.clothing)||'--');
      txt('mlth',cl(cd.inner_thought)||'...');
    }catch(e){}
  }

  setInterval(update,2000);
  update();
});
